  (5, 'sXcqRkyfx6Q', 'John Will and David Meyer demonstrate the basic scissor sweep from closed guard, emphasizing posture control and details to make the sweep effective vs resistance.', '2025-12-25T02:16:34.670867', '2025-12-25T02:16:34.670867', 'gi', 1, 1, 'https://img.youtube.com/vi/sXcqRkyfx6Q/0.jpg', 'Scissor Sweep By John Will'),
  (6, 'L5OvifH8O14', 'John Will and David Meyer demonstrate a double ankle sweep vs an ignorant standing opponent in the closed guard with details on how to come up on top with double outside foot position', '2025-12-25T02:24:15.594568', '2025-12-25T02:24:15.594568', 'gi', 1, 1, 'https://img.youtube.com/vi/L5OvifH8O14/0.jpg', 'Double Ankle Sweep From Closed Guard by John Will'),
