  (8, '0Q4pp5eF9D0', 'Lachlan Giles shows a basic Rear Naked Choke.  Includes basic details for complete beginners often skipped in more advanced material.', '2025-12-25T03:11:59.393105', '2025-12-25T03:11:59.393105', 'no_gi', 1, 1, 'https://img.youtube.com/vi/0Q4pp5eF9D0/0.jpg', 'Rear Naked Choke By Lachlan Giles'),
